package jetbrains.mps.java.workbench.actions;

/*Generated by MPS */

import jetbrains.mps.ide.embeddableEditor.EmbeddableEditor;
import jetbrains.mps.project.Project;
import java.beans.Transient;
import java.awt.Dimension;

/**
 * Embeddable editor with a minimal size corresponding to the preferred size of the component.
 * 
 * A maximal minimum height is provided so when the preferred height is above that value, the minimum height
 * does not exceed it. Same principle is applied for width, except the default max size for code is used instead.
 */
public class SizedEmbeddableEditor extends EmbeddableEditor {
  private final int myMaxMinimumHeight;

  public SizedEmbeddableEditor(Project project, boolean editable, int maxMinimumHeight) {
    super(project, editable);
    myMaxMinimumHeight = maxMinimumHeight;
  }

  @Transient
  @Override
  public Dimension getMinimumSize() {
    // Max x of the editor + small margin
    int rightMargin = this.getEditor().getCurrentEditorComponent().getEditorComponentSettings().getRightMargin() + 100;

    // Try to fit the preferred size, only if it is not greater than the specified size
    Dimension prefered = this.getPreferredSize();
    return new Dimension(Math.min(rightMargin, (int) prefered.getWidth()), Math.min(myMaxMinimumHeight, (int) prefered.getHeight()));
  }

}
